10	
11	int test(char* fname_inOut,
12	        char* fname_golden,
13	        uint32_t size)
14	{
15	    {
16	        dump_param("size=%" PRIu32, size);
17	    }
18	
19	    FILE *fptr_in_out, *fptr_golden;
20	    //backup originally malloced starting address for later memory releasing
21	    void *in_out_ori, *golden_ori;
22	
23	    q7_t *in_out = (q7_t*)test_malloc(sizeof(q7_t) * size, "in_out", &in_out_ori);
24	    q7_t *golden = (q7_t*)test_malloc(sizeof(q7_t) * size, "golden", &golden_ori);
25	
26	    test_Fopen(fname_inOut, "rb", &fptr_in_out);
27	    test_Fread(in_out, sizeof(*in_out), size, fptr_in_out, "in_out");
28	    process_after_reading_input_data();
29	
30	#ifdef ENA_RUN_TWICE
31	    riscv_nn_relu_s8(in_out, size);
32	#endif
33	
34	    process_before_perf_measuring();
35	#ifdef PF_COUNTER
36	    startPFM;
37	#endif
38	    riscv_nn_relu_s8(in_out, size);
39	#ifdef PF_COUNTER
40	    stopPFM;
41	    readResult();
42	#endif
43	
44	#if ENA_DUMP_GOLDEN
45	    test_Fopen(fname_golden, "wb+", &fptr_golden);
46	    fwrite(in_out, sizeof(*golden), size, fptr_golden);
47	    uint32_t retStatus = NDS_SUCCESS;
48	#else
49	    test_Fopen(fname_golden, "rb", &fptr_golden);
50	    test_Fread(golden, sizeof(*golden), size, fptr_golden, "golden");
51	    uint32_t retStatus = verify_buffer(in_out, golden, size, sizeof(*in_out), 0);
52	#endif
53	
54	    test_free(&in_out_ori);
55	    test_free(&golden_ori);
56	    fclose(fptr_in_out);
57	    fclose(fptr_golden);
58	
59	    return retStatus;
60	}
61	
62	int main (void)
63	{
64	    enable_fs_and_vs();
65	    uint32_t size;
66	    uint32_t retStatus=NDS_SUCCESS;
67	
68	#if !ENA_MEASURE_PERF
69	    //test-1: column length less than VLEN
70	    size = 3;
71	    retStatus |= test("8b_in1.bin", "relu_q7_golden.bin", size);
72	
73	    //test-2: column length more than VLEN
74	    size = 71;
75	    retStatus |= test("8b_in1.bin", "relu_q7_golden2.bin", size);
76	#endif
77	
78	    //test-3: max column length
79	    size = 65535;
80	    retStatus |= test("8b_in1.bin", "relu_q7_golden3.bin", size);
81	
82	    return retStatus;
83	}
